// Generated by OrchestKit Claude Plugin
// Created: 2026-06-07

import { COUNTS, SITE } from "@/lib/constants";
import { orderedPages, readDocBody } from "@/lib/docs-content";

// /llms-full.txt — the entire documentation as one Markdown file so an agent can
// ingest everything in a single request. Narrative sections are included in full
// first; once the budget is reached, remaining pages (the large auto-generated
// reference) degrade to a titled link so the file stays under the 200,000-char
// ceiling that lets a 64k-token agent read it in one pass.
export const dynamic = "force-dynamic";

// Stay comfortably under the 200k spec ceiling, leaving room for the header.
const MAX_CHARS = 190_000;

function header(): string {
	return [
		`# ${SITE.name} — Full Documentation`,
		"",
		`> ${SITE.name} is a free, open-source plugin for Claude Code: ${COUNTS.skills} skills, ${COUNTS.agents} agents, and ${COUNTS.hooks} lifecycle hooks with built-in security patterns and quality gates.`,
		"",
		"## Quickstart",
		"",
		`1. Install Claude Code ${SITE.ccVersion}.`,
		`2. Run \`${SITE.installCommand}\`.`,
		"3. Invoke any skill with `/ork:<skill>` (e.g. `/ork:implement`, `/ork:review-pr`).",
		"",
		"## API",
		"",
		`- **Search** — \`GET ${SITE.domain}/api/search?query=...\` returns JSON results. OpenAPI: ${SITE.domain}/api/openapi`,
		`- **Ask** (natural language) — \`POST ${SITE.domain}/ask\` returns JSON (NLWeb); send \`Accept: text/event-stream\` for SSE streaming.`,
		`- **MCP server** (Streamable HTTP) — ${SITE.domain}/api/mcp · card: ${SITE.domain}/.well-known/mcp/server-card.json`,
		`- **Markdown** — append \`.md\` to any page URL, or send \`Accept: text/markdown\`.`,
		`- **API catalog** (RFC 9727) — ${SITE.domain}/.well-known/api-catalog`,
		"",
		"## Authentication",
		"",
		`The public documentation and search API require no authentication — agents call the endpoints directly. Details: ${SITE.domain}/auth.md`,
		"",
		"---",
		"",
	].join("\n");
}

export async function GET() {
	const head = header();
	const parts: string[] = [head];
	let size = head.length;
	let truncated = false;

	for (const page of orderedPages()) {
		const url = `${SITE.domain}${page.url}`;
		const heading = `\n\n## ${page.data.title}\n\n${page.data.description ?? ""}\n\n[${url}](${page.url})`;

		if (size + heading.length > MAX_CHARS) {
			truncated = true;
			continue;
		}

		const body = await readDocBody(page.slugs);
		const block = body ? `${heading}\n\n${body}` : heading;

		if (size + block.length > MAX_CHARS) {
			// Body would overflow — keep the titled link, drop the body.
			parts.push(heading);
			size += heading.length;
			truncated = true;
		} else {
			parts.push(block);
			size += block.length;
		}
	}

	if (truncated) {
		parts.push(
			`\n\n---\n\n> Some pages above are listed as links only to keep this file under 200,000 characters. Fetch any page's full Markdown by appending \`.md\` to its URL, or read the navigation index at ${SITE.domain}/llms.txt and per-section index at ${SITE.domain}/docs/llms.txt.\n`,
		);
	}

	return new Response(parts.join(""), {
		headers: {
			"Content-Type": "text/markdown; charset=utf-8",
			"Cache-Control": "public, max-age=3600",
		},
	});
}
